// Show center marker for precise centering
SpecialMarkersMgr.setFlagFOVCenterMarker(true);

// Hide center marker
SpecialMarkersMgr.setFlagFOVCenterMarker(false);

// Read current state (alternative method)
var visible = core.getStelProperty('SpecialMarkersMgr.fovCenterMarkerDisplayed');

if (SpecialMarkersMgr.getFlagFOVCenterMarker()) {
    core.debug("FOV center crosshair is visible");
}

// Set FOV center marker to red
var red = core.vec3f(1.0, 0.0, 0.0);
SpecialMarkersMgr.setColorFOVCenterMarker(red);

// Set to cyan
var cyan = core.vec3f(0.0, 0.8, 0.9);
SpecialMarkersMgr.setColorFOVCenterMarker(cyan);

// Show circular FOV marker for eyepiece simulation
SpecialMarkersMgr.setFlagFOVCircularMarker(true);
SpecialMarkersMgr.setFOVCircularMarkerSize(1.0);

// Hide circular marker
SpecialMarkersMgr.setFlagFOVCircularMarker(false);

if (SpecialMarkersMgr.getFlagFOVCircularMarker()) {
    core.debug("Circular FOV marker is visible");
}

// Set circular marker to 1 degree (typical eyepiece)
SpecialMarkersMgr.setFOVCircularMarkerSize(1.0);

// Set to 30 arcminutes for a finder scope
SpecialMarkersMgr.setFOVCircularMarkerSize(0.5);

// Enable the marker
SpecialMarkersMgr.setFlagFOVCircularMarker(true);

// Set circular FOV marker to green
var green = core.vec3f(0.2, 0.8, 0.2);
SpecialMarkersMgr.setColorFOVCircularMarker(green);

// Show rectangular FOV marker for camera framing
SpecialMarkersMgr.setFlagFOVRectangularMarker(true);
SpecialMarkersMgr.setFOVRectangularMarkerWidth(2.0);
SpecialMarkersMgr.setFOVRectangularMarkerHeight(1.5);

if (SpecialMarkersMgr.getFlagFOVRectangularMarker()) {
    core.debug("Rectangular FOV marker is visible");
}

// Set rectangular marker to 2° x 1.5°
SpecialMarkersMgr.setFOVRectangularMarkerWidth(2.0);
SpecialMarkersMgr.setFOVRectangularMarkerHeight(1.5);
SpecialMarkersMgr.setFlagFOVRectangularMarker(true);

// Rotate the marker 45 degrees
SpecialMarkersMgr.setFOVRectangularMarkerRotationAngle(45.0);

// Reset rotation
SpecialMarkersMgr.setFOVRectangularMarkerRotationAngle(0.0);

// Set rectangular FOV marker to yellow
var yellow = core.vec3f(1.0, 1.0, 0.2);
SpecialMarkersMgr.setColorFOVRectangularMarker(yellow);

// Show compass marks for orientation
SpecialMarkersMgr.setFlagCompassMarks(true);

// Hide compass marks
SpecialMarkersMgr.setFlagCompassMarks(false);

if (SpecialMarkersMgr.getFlagCompassMarks()) {
    core.debug("Compass marks are visible");
}

// Set compass marks to light blue
var lightBlue = core.vec3f(0.5, 0.7, 1.0);
SpecialMarkersMgr.setColorCompassMarks(lightBlue);
